// 1. Obtenemos los datos brutos
let rawData = $input.first().json.data;
if (typeof rawData === 'string') rawData = JSON.parse(rawData);

const infoBase = rawData[0]; // Aquí está el nombre y provincia
const prediccionMañana = infoBase.prediccion.dia[1];

const horasLimpias = prediccionMañana.temperatura.map((item) => {
  const hora = item.periodo;
  const rachaViento = prediccionMañana.vientoAndRachaMax.find(v => v.periodo === hora && v.value !== undefined);

  return {
    h: hora + ":00",
    temp: parseInt(item.value),
    hum: parseInt(prediccionMañana.humedadRelativa.find(h => h.periodo === hora)?.value || 0),
    cielo: prediccionMañana.estadoCielo.find(c => c.periodo === hora)?.descripcion || "Despejado",
    precip: prediccionMañana.precipitacion.find(p => p.periodo === hora)?.value || "0",
    viento: parseInt(rachaViento?.value || 0)
  };
});

return {
  municipio: infoBase.nombre,
  provincia: infoBase.provincia,
  fecha: prediccionMañana.fecha.split('T')[0],
  amanecer: prediccionMañana.orto,
  atardecer: prediccionMañana.ocaso,
  datos_horarios: horasLimpias
};

// 1. Obtenemos el array PVPC del nodo anterior
const rawData = $input.first().json.PVPC;

// Verificación de seguridad
if (!rawData || rawData.length === 0) {
  return { datos_electricos: [], error: "No se han recibido datos de Red Eléctrica" };
}

// 2. Detectamos si es fin de semana (Sábado=6, Domingo=0)
const [dia, mes, anio] = rawData[0].Dia.split('/');
const fechaObjeto = new Date(anio, mes - 1, dia);
const esFinDeSemana = (fechaObjeto.getDay() === 0 || fechaObjeto.getDay() === 6);

// 3. Procesamos las 24 horas y las guardamos en una constante
const listaProcesada = rawData.map(item => {
  const precioMWh = parseFloat(item.PCB.replace(',', '.'));
  const precioKWhNum = precioMWh / 1000;
  const peaje = parseFloat(item.TEUPCB.replace(',', '.'));

  // Lógica de tramo horario técnico (Peajes)
  let tramoHorario = "PUNTA (Caro)";
  if (peaje < 10) {
    tramoHorario = "VALLE (Barato)";
  } else if (peaje < 40) {
    tramoHorario = "LLANO (Medio)";
  }

  // Lógica de color de energía (Bolsillo)
  let tramoColor = "ROJO";
  let recomendacion = "Evitar consumo alto";

  if (precioKWhNum < 0.10) {
    tramoColor = "VERDE";
    recomendacion = "Ideal para grandes consumos y climatización";
  } else if (precioKWhNum <= 0.15) {
    tramoColor = "AMARILLO";
    recomendacion = "Uso moderado";
  }

  return {
    hora: `${item.Hora.split('-')[0]}:00`,
    // Solo enviamos el dato formateado para ahorrar espacio
    precio: `${precioKWhNum.toFixed(5).replace('.', ',')} €/kWh`,
    tramo: esFinDeSemana ? "VALLE (Fin de semana)" : tramoHorario,
    color: tramoColor,
    sugerencia: recomendacion
  };
});

// 4. Retorno del objeto empaquetado para el Merge
return {
  datos_electricos: listaProcesada
};
